Here's the XAML and ViewModel setup:

### XAML

```xml
<RefreshView IsRefreshing="{Binding IsRefreshing}"
             Command="{Binding RefreshCommand}">
    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding CurrentItem, Mode=TwoWay}"
                    SelectionChangedCommand="{Binding ItemSelectedCommand}">
        <CollectionView.ItemTemplate>
            <DataTemplate x:DataType="models:Item">
                <Grid Padding="12" ColumnDefinitions="48,*">
                    <Image Source="{Binding Icon}"
                           WidthRequest="40" HeightRequest="40" />
                    <Label Grid.Column="1"
                           Text="{Binding Name}"
                           VerticalOptions="Center" />
                </Grid>
            </DataTemplate>
        </CollectionView.ItemTemplate>
    </CollectionView>
</RefreshView>
```

### ViewModel Bindings

```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private ObservableCollection<Item> _items = new();

    [ObservableProperty]
    private Item? _currentItem;

    [ObservableProperty]
    private bool _isRefreshing;

    [RelayCommand]
    private async Task RefreshAsync()
    {
        var data = await _api.GetItemsAsync();
        Items = new ObservableCollection<Item>(data);
        IsRefreshing = false;  // Must set false to dismiss spinner
    }

    [RelayCommand]
    private async Task ItemSelectedAsync()
    {
        if (CurrentItem is null) return;
        await _nav.GoToAsync("DetailPage", new Dictionary<string, object>
        {
            ["Item"] = CurrentItem
        });
        CurrentItem = null;  // Reset so same item can be re-selected
    }
}
```

### Key points

| Binding | Purpose |
|---|---|
| `IsRefreshing` â†’ `bool` | Controls the refresh spinner; **set to `false`** when done |
| `Command` â†’ `RefreshCommand` | Fires on pull-to-refresh to reload from API |
| `SelectedItem` â†’ `CurrentItem` (TwoWay) | Tracks the selected item |
| `SelectionChangedCommand` â†’ `ItemSelectedCommand` | Fires on selection to trigger navigation |
| `ItemsSource` â†’ `ObservableCollection<T>` | **Must** be `ObservableCollection`, not `List`, for live UI updates |

Reset `CurrentItem = null` after navigation so the user can tap the same item again.
